#include <bits/stdc++.h>
#define x first
#define y second
using namespace std;
typedef pair<int,int> pii;

const int N=1e5+10;

struct Node{
    int op,x,y;
}p[N];

int n,q,f[N],fa[N],dep[N],dfn[N],num,sz[N],c[N];
vector<int> g[N];

void add(int x,int k){
    if(!x)
        return;
    for(;x<=n;x+=(x&(-x)))
        c[x]+=k;
}

int ask(int x){
    int res=0;
    for(;x;x-=(x&(-x)))
        res+=c[x];
    return res;
}

void dfs(int x,int lst){
    sz[x]=1;
    fa[x]=lst;
    dep[x]=dep[fa[x]]+1;
    dfn[x]=++num;
    for(int y:g[x])
        if(y!=fa[x]){
            dfs(y,x);
            sz[x]+=sz[y];
        }
}

int father(int x){
    return f[x]==x?x:f[x]=father(f[x]);
}

int cal(int x){
    return ask(dfn[x]+sz[x]-1)-ask(dfn[x]-1);
}

int main(){
    scanf("%d%d",&n,&q);
    for(int i=1;i<=n;i++)
        f[i]=i;
    for(int i=1;i<=q;i++){
        char op[2];
        int x,y;
        scanf("%s",op);
        scanf("%d%d",&x,&y);
        if(op[0]=='A'){
            g[x].push_back(y);
            g[y].push_back(x);
            f[father(y)]=father(x);
            p[i]={0,x,y};
        }else
            p[i]={1,x,y};
    }
    int lst=0;
    for(int i=1;i<=n;i++)
        if(f[i]==i){
            if(lst){
                g[lst].push_back(i);
                g[i].push_back(lst);
            }
            lst=i;
        }
    dfs(1,0);
    for(int i=1;i<=n;i++){
        add(dfn[i],1);
        add(dfn[fa[i]],-1);
        f[i]=i;
    }
    for(int i=1;i<=q;i++){
        if(dep[p[i].x]>dep[p[i].y])
            swap(p[i].x,p[i].y);
        int siz=cal(p[i].y);
        if(p[i].op==0){
            int fx=father(p[i].x);
            add(dfn[p[i].x],siz);
            add(dfn[fa[fx]],-siz);
            f[p[i].y]=fx;
        }else
            printf("%lld\n",1ll*siz*(cal(father(p[i].y))-siz));
    }
    return 0;
}
